const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'math-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение'}}];
}

// Защита от SQL-инъекций через session_id
if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{json: {valid: 0, error: 'session_id содержит недопустимые символы'}}];
}

if (message.length > 100000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 100000 символов)'}}];
}

return [{json: {valid: 1, message: message, session_id: session_id}}];

const agg = $('Агрегация').first().json;
const message = agg.message;
const historyContext = agg.historyContext || '';
const historyContextMath = agg.historyContextMath || '';
const session_id = agg.session_id || 'math-default';
const lower = message.toLowerCase();

// 1) Вложение в math-агенте форсит math ТОЛЬКО при наличии мат-индикаторов
// в содержимом. Раньше любое вложение шло в math: пользователь иногда по
// ошибке прикреплял рецепт/художку, LLM пытался писать Python и валился
// без понятной обратной связи. Теперь:
//   - есть арифметическое выражение / переменная / мат-термин → math
//   - чистая проза (рецепт, статья) → проваливаемся в обычный классификатор
//     (там скорее всего попадёт в general, и пользователь получит честный
//     ответ «не могу помочь с этим типом задач»).
if (/\[ВЛОЖЕНИЕ:/.test(message)) {
  const hasOperators = /\d+\s*[+\-*/^%=]\s*\d/.test(message);
  const hasEquations = /(x|y|z|икс|игрек)\s*[\^+\-*/=]/i.test(message);
  const hasMathTerm = /(уравнен|формул|вычисл|реши|сколько|корен|интеграл|производн|сумм|процент|матриц|треугольник|периметр|площад|объ[её]м|радиус|диаметр|графи[кч]|функци|медиан|среднее|задач|пример)/i.test(message);
  if (hasOperators || hasEquations || hasMathTerm) {
    return [{ json: { message, mode: 'math', historyContext, historyContextMath, session_id } }];
  }
  // нет мат-индикаторов в вложении — пускаем в обычный классификатор ниже
}

const mathKeywords = [
  'посчитай', 'вычисли', 'вычислить', 'рассчитай', 'рассчитать',
  'реши', 'решить', 'решение', 'уравнен', 'неравенств',
  'формул', 'процент', 'корень', 'степен', 'логарифм',
  'сумм', 'разност', 'произведен', 'делен', 'остаток от',
  'плюс', 'минус', 'умножь', 'умножить', 'умножен',
  'раздели', 'разделить',
  'возведи', 'возвести', 'в степени', 'в квадрате', 'в кубе',
  'площад', 'объём', 'объем', 'периметр', 'окружност',
  'треугольник', 'квадрат', 'куб', 'прямоугольник', 'цилиндр', 'сфер',
  'интеграл', 'производн', 'предел', 'синус', 'косинус', 'тангенс',
  'матриц', 'вектор', 'определител', 'детерминант',
  'график', 'функци', 'парабол',
  'статистик', 'среднее', 'медиан', 'дисперс', 'отклонен',
  'вероятност', 'комбинатор', 'факториал', 'перестанов', 'сочетан',
  'npv', 'irr', 'roi', 'аннуитет', 'ипотек', 'кредит', 'депозит',
  'инвестиц', 'маржа', 'наценк', 'скидк', 'ндс', 'налог',
  'зарплат', 'рентабельн', 'прибыл', 'выручк', 'себестоимост',
  'сколько будет', 'чему равн', 'найди', 'найти',
  'sqrt', 'calculate', 'solve', 'equation', 'math',
  'конвертируй', 'переведи в'
];

const hasMathExpression = /\d+\s*[+\-*/^%=]\s*\d+/.test(message);
const hasFactorial = /\d+\s*!/.test(message);
const hasNumbers = /\d{2,}/.test(message) || /\d+[.,]\d+/.test(message);

let isMath = hasMathExpression || hasFactorial;

if (!isMath) {
  for (const kw of mathKeywords) {
    if (lower.includes(kw)) { isMath = true; break; }
  }
}

if (!isMath && hasNumbers && message.length > 20) {
  const taskIndicators = ['сколько', 'какой', 'какая', 'какое', 'найди', 'найти',
    'определи', 'определить', 'если', 'при', 'дано', 'равно', 'равна'];
  for (const kw of taskIndicators) {
    if (lower.includes(kw)) { isMath = true; break; }
  }
}

if (!isMath && /^[\d\s+\-*/^().,]+$/.test(message.trim())) {
  isMath = true;
}

if (!isMath) {
  return [{ json: { message, mode: 'general', historyContext, historyContextMath, session_id } }];
}

return [{ json: { message, mode: 'math', historyContext, historyContextMath, session_id } }];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'Не удалось обработать запрос. Попробуйте ещё раз.', code: '', raw_result: '' } }];
  }
  // Безопасный доступ — LLM при таймауте может вернуть пустой output
  const text = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!text) {
    return [{ json: { response: 'Пустой ответ от LLM. Попробуйте ещё раз.', code: '', raw_result: '' } }];
  }
  return [{ json: { response: text.trim(), code: '', raw_result: '' } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки.', code: '', raw_result: '' } }];
}

try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{ json: { success: 0, code: '', error: 'GigaChat недоступен. Попробуйте позже.' } }];
  }

  let code = raw.output[0].content[0].text;

  // Убираем markdown-обёртки
  code = code.replace(/```python\s*/gi, '').replace(/```\s*/g, '').trim();

  // Убираем текст до первого import или первой переменной
  const lines = code.split('\n');
  let startIdx = 0;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line.startsWith('import ') || line.startsWith('from ') ||
        line.match(/^[a-zA-Z_]/) || line.startsWith('#') ||
        line.startsWith('print(')) {
      startIdx = i;
      break;
    }
  }
  code = lines.slice(startIdx).join('\n').trim();

  if (!code || code.length < 5) {
    return [{ json: { success: 0, code: '', error: 'GigaChat не смог сгенерировать код.' } }];
  }

  // ПРОВЕРКА БЕЗОПАСНОСТИ
  // На Варианте A в Pyodide-бандле только stdlib — sympy/numpy/scipy и т.п.
  // отсутствуют. Если LLM их импортирует, упадёт ModuleNotFoundError + Pyodide
  // полезет в CDN с DNS-таймаутом. Лучше ловить тут и сразу отвечать
  // понятной ошибкой.
  const dangerous = [
    // Опасный системный доступ — import X
    'import os', 'import sys', 'import subprocess', 'import shutil',
    'import pathlib', 'import socket', 'import http', 'import requests',
    'import urllib', 'import ftplib', 'import smtplib', 'import pickle',
    // Опасный системный доступ — from X import / from X.Y import
    'from os ', 'from os.', 'from sys ', 'from sys.',
    'from subprocess ', 'from subprocess.',
    'from shutil ', 'from shutil.',
    'from pathlib ', 'from pathlib.',
    'from socket ', 'from socket.',
    'from http ', 'from http.',
    'from requests ', 'from requests.',
    'from urllib ', 'from urllib.',
    'from ftplib ', 'from ftplib.',
    'from smtplib ', 'from smtplib.',
    'from pickle ', 'from pickle.',
    // Недоступные модули (нет в Pyodide-core бандле) — ловим до runtime
    'import sympy', 'from sympy ', 'from sympy.',
    'import numpy', 'from numpy ', 'from numpy.',
    'import scipy', 'from scipy ', 'from scipy.',
    'import pandas', 'from pandas ', 'from pandas.',
    'import matplotlib', 'from matplotlib ', 'from matplotlib.',
    'import sklearn', 'from sklearn ', 'from sklearn.',
    // Опасные builtins
    'open(', 'exec(', 'eval(', '__import__', 'compile(',
    'globals(', 'locals(', 'getattr(', 'setattr(', 'delattr(',
    'os.', 'sys.', 'subprocess.', 'shutil.', 'pathlib.',
    'socket.', 'requests.', 'input('
  ];

  const codeLower = code.toLowerCase();
  for (const d of dangerous) {
    if (codeLower.includes(d.toLowerCase())) {
      return [{ json: { success: 0, code: code, error: 'Код содержит запрещённую операцию: ' + d } }];
    }
  }

  // Если LLM забыла print() — пытаемся найти последнюю присвоенную
  // переменную regex'ом и напечатать её с маркером ОТВЕТ:.
  // Слепое `print(result)` падало с NameError если LLM назвала переменную
  // иначе (x, final, answer и т.п.).
  if (!code.includes('print(') && !code.includes('print (')) {
    const assignments = [...code.matchAll(/^[\t ]*([a-zA-Z_][a-zA-Z0-9_]*)\s*=(?!=)/gm)];
    if (assignments.length > 0) {
      const lastVar = assignments[assignments.length - 1][1];
      code += `\nprint(f"ОТВЕТ: {${lastVar}}")`;
    } else {
      // Нет ни print, ни присваиваний — код некорректен
      return [{ json: { success: 0, code: code, error: 'GigaChat сгенерировал код без вывода. Попробуйте перефразировать задачу.' } }];
    }
  }

  return [{ json: { success: 1, code: code, error: '' } }];

} catch (e) {
  return [{ json: { success: 0, code: '', error: 'Ошибка обработки ответа GigaChat: ' + e.message } }];
}

const historyRows = $input.all().reverse();
let historyContext = '';
let historyContextMath = '';
if (historyRows.length > 0) {
  const allLines = historyRows.map(item => {
    const role = item.json.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (item.json.content || '');
  });
  // Полный контекст — для GENERAL-ветки (chit-chat, нужна связность диалога).
  historyContext = 'История диалога:\n' + allLines.join('\n') + '\n\n';
  // Урезанный контекст — для MATH-ветки. Математика обычно stateless,
  // длинная история сбивает тупой LLM при кодогенерации (он может
  // решать старую задачу из истории). Берём только 3 последние пары.
  const lastSix = allLines.slice(-6);
  if (lastSix.length > 0) {
    historyContextMath = 'История диалога:\n' + lastSix.join('\n') + '\n\n';
  }
}
const v = $('Валидация').first().json;
return [{json: {message: v.message, session_id: v.session_id, historyContext, historyContextMath}}];

// Phase 2 — фронт уже исполнил Python в Pyodide и шлёт результат.
// Достаём поля и нормализуем. final_line — это значение после маркера
// «ОТВЕТ: », отделённое от полного raw_result для удобства подстановки.
// exec_killed — true если Pyodide убит по таймауту (frontend сделал
// worker.terminate). Отличается от exec_error: kill это не Python
// exception, а внешнее прерывание; формулировка ответа другая.
const body = $input.first().json.body || {};
const session_id = (body.session_id || 'math-default').trim();

// Защита от SQL-инъекций (этот session_id уйдёт в queryReplacement позже)
if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{json: {error: 'session_id содержит недопустимые символы'}}];
}

// Защита от DoS: ограничиваем длину пользовательских полей.
// Pyodide-результат большой = переполнение БД и chat_memory.
const code = (body.code || '').toString();
const raw_result = (body.raw_result || '').toString();
const final_line = (body.final_line || '').toString().trim();
const message = (body.message || '').toString().trim();
if (code.length > 50000) return [{json: {error: 'code слишком длинный (>50KB)'}}];
if (raw_result.length > 50000) return [{json: {error: 'raw_result слишком длинный (>50KB)'}}];
if (final_line.length > 5000) return [{json: {error: 'final_line слишком длинный (>5KB)'}}];
if (message.length > 100000) return [{json: {error: 'message слишком длинный'}}];

return [{json: {
  message: message,
  session_id: session_id,
  code: code,
  raw_result: raw_result,
  final_line: final_line,
  exec_error: (body.error || '').toString().slice(0, 5000),
  exec_killed: !!body.killed
}}];

